CREATE POLICY "Admins can read prayers bucket" ON storage.objects FOR SELECT TO authenticated USING (bucket_id = 'prayers' AND public.has_role(auth.uid(), 'admin'::public.app_role));
CREATE POLICY "Admins can upload to prayers bucket" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'prayers' AND public.has_role(auth.uid(), 'admin'::public.app_role));
CREATE POLICY "Admins can update prayers bucket" ON storage.objects FOR UPDATE TO authenticated USING (bucket_id = 'prayers' AND public.has_role(auth.uid(), 'admin'::public.app_role)) WITH CHECK (bucket_id = 'prayers' AND public.has_role(auth.uid(), 'admin'::public.app_role));
CREATE POLICY "Admins can delete from prayers bucket" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'prayers' AND public.has_role(auth.uid(), 'admin'::public.app_role));